  @override
  String get eulaTitle => 'Συμφωνία Άδειας Χρήσης Τελικού Χρήστη (EULA)';

  @override
  String get eulaArticle1 =>
      'Άρθρο 1 (Παραχώρηση Άδειας)\nΑυτή η εφαρμογή (\"Tarot Witch\") παραχωρεί δικαιώματα χρήσης μόνο για προσωπική, μη εμπορική χρήση και η ιδιοκτησία ή τα δικαιώματα πνευματικής ιδιοκτησίας της εφαρμογής δεν μεταβιβάζονται.\n\n';

  @override
  String get eulaArticle2 =>
      'Άρθρο 2 (Απαγορευμένη Χρήση)\nΟ χρήστης δεν επιτρέπεται να χρησιμοποιεί αυτήν την υπηρεσία για παράνομους σκοπούς ή για σκοπούς που παραβιάζουν τα δικαιώματα τρίτων, ούτε να χειρίζεται αυθαίρετα το σύστημα ή τα δεδομένα ή να κάνει αντίστροφη μηχανική.\n\n';

  @override
  String get eulaArticle3 =>
      'Άρθρο 3 (Συλλογή Δεδομένων και Περίοδος Αποθήκευσης)\nΓια την ομαλή παροχή υπηρεσιών, τα δεδομένα του ημερολογίου ταρώ και των σχετικών προβλέψεων που δημιουργεί ο χρήστης αποθηκεύονται με ασφάλεια για μια βασική περίοδο 3 ετών από την ημερομηνία δημιουργίας.\n\n';

  @override
  String get eulaArticle4 =>
      'Άρθρο 4 (Χειρισμός αδρανούς λογαριασμού λόγω μακροχρόνιας μη σύνδεσης)\nΕάν ο χρήστης δεν συνδεθεί στην υπηρεσία για περισσότερο από 1 έτος (365 ημέρες), ο λογαριασμός θα μετατραπεί σε αδρανή λογαριασμό και όλα τα δεδομένα του χρήστη θα διαγραφούν αυτόματα χωρίς προηγούμενη ειδοποίηση, για την προστασία των προσωπικών δεδομένων και τη διατήρηση ενός ομαλού περιβάλλοντος διακομιστή.\n\n';

  @override
  String get eulaArticle5 =>
      'Άρθρο 5 (Καταστροφή Δεδομένων και Μη Δυνατότητα Ανάκτησης)\nΤα δεδομένα που έχουν παρέλθει την περίοδο αποθήκευσης του Άρθρου 3 ή έχουν διαγραφεί σύμφωνα με το Άρθρο 4 καταστρέφονται οριστικά και δεν μπορούν να ανακτηθούν σε καμία περίπτωση.\n\n';

  @override
  String get eulaArticle6 =>
      'Άρθρο 6 (Αποποίηση Εγγύησης και Απαλλαγή Ευθύνης)\nΟι προβλέψεις και οι ερμηνείες ταρώ που παρέχονται από αυτήν την εφαρμογή προορίζονται μόνο για ψυχαγωγικούς σκοπούς και δεν αντικαθιστούν νομικές, ιατρικές ή οικονομικές συμβουλές. Ο προγραμματιστής δεν φέρει ευθύνη για οποιεσδήποτε άμεσες ή έμμεσες ζημίες προκύψουν από τη χρήση της υπηρεσίας.\n\n';

  @override
  String get eulaAgreement =>
