  @override
  String get pushArticle1 =>
      'Άρθρο 1 (Σκοπός)\nΑυτή η συγκατάθεση αποσκοπεί στην αποστολή διαφημιστικών πληροφοριών, όπως χρήσιμες εκδηλώσεις, προσφορές και νέες ενημερώσεις ωροσκοπίων, μέσω ειδοποιήσεων push στους χρήστες της υπηρεσίας Tarot Witch.\n\n';

  @override
  String get pushArticle2 =>
      'Άρθρο 2 (Ανάκληση Συγκατάθεσης)\nΟ χρήστης μπορεί να ανακαλέσει αυτή τη συγκατάθεση ανά πάσα στιγμή από το [Το Μενού μου > Ρυθμίσεις Εφαρμογής] εντός της εφαρμογής. Ακόμα και αν ανακληθεί η συγκατάθεση, οι βασικές λειτουργίες της υπηρεσίας (απαραίτητες υπηρεσίες) μπορούν να χρησιμοποιηθούν κανονικά.\n\n';

  @override
